import{_ as p,c as t}from"./app.0b00aae6.js";const r={},s=t('<h1 id="_11-\u8BB2-\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u5E94\u8BE5\u5982\u4F55\u8BBE\u8BA1" tabindex="-1"><a class="header-anchor" href="#_11-\u8BB2-\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u5E94\u8BE5\u5982\u4F55\u8BBE\u8BA1" aria-hidden="true">#</a> 11 \u8BB2\uFF1A\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u5E94\u8BE5\u5982\u4F55\u8BBE\u8BA1\uFF1F</h1><p>\u5728\u4E0A\u4E00\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u8DDF\u4F60\u5206\u4EAB\u4E86\u505A\u597D\u4E92\u8054\u7F51\u4EA7\u54C1\u6D4B\u8BD5\u4F60\u8981\u5177\u5907\u7684\u975E\u6D4B\u8BD5\u77E5\u8BC6\uFF0C\u90A3\u4E48\u73B0\u5728\u6211\u5C31\u6765\u8DDF\u4F60\u804A\u804A\u5E94\u8BE5\u5982\u4F55\u8BBE\u8BA1\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u3002</p><p>\u5728\u6211\u5F00\u59CB\u4ECA\u5929\u7684\u8BDD\u9898\u4E4B\u524D\uFF0C\u8BF7\u4F60\u5148\u601D\u8003\u4E00\u4E0B\u4E3A\u4EC0\u4E48\u6211\u4F1A\u628A\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u5355\u72EC\u62FF\u51FA\u6765\u8BA8\u8BBA\uFF0C\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u548C\u4F20\u7EDF\u8F6F\u4EF6\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u5230\u5E95\u6709\u54EA\u4E9B\u4E0D\u540C\uFF1F</p><p><strong>\u7814\u53D1\u6D41\u7A0B\u7684\u4E0D\u540C\u51B3\u5B9A\u4E86\u6D4B\u8BD5\u7B56\u7565\u7684\u4E0D\u540C</strong></p><p>\u5982\u679C\u76F4\u63A5\u56DE\u7B54\u4E92\u8054\u7F51\u4EA7\u54C1\u548C\u4F20\u7EDF\u8F6F\u4EF6\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u6709\u4F55\u4E0D\u540C\uFF0C\u4F60\u4F1A\u6709\u4E9B\u6478\u4E0D\u7740\u5934\u8111\uFF0C\u90A3\u4E48\u6309\u7167\u6211\u4E00\u76F4\u5728\u5F3A\u8C03\u7684\u77E5\u5176\u7136\u77E5\u5176\u6240\u4EE5\u7136\u7684\u539F\u5219\uFF0C\u4F60\u53EF\u4EE5\u5148\u53BB\u603B\u7ED3\u8FD9\u4E24\u7C7B\u4EA7\u54C1\u7684\u7814\u53D1\u672C\u8EAB\u6700\u5927\u7684\u4E0D\u540C\u662F\u4EC0\u4E48\uFF1F</p><p><strong>\u90A3\u5C31\u662F\uFF0C\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u201C\u5FEB\u201D</strong>\u3002</p><p>\u6211\u5728\u4E13\u680F\u524D\u9762\u7684\u6587\u7AE0\u4E2D\uFF0C\u5DF2\u7ECF\u63D0\u5230\u4E86\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u4E0A\u7EBF\u5468\u671F\u901A\u5E38\u662F\u4EE5\u201C\u5929\u201D\u751A\u81F3\u662F\u4EE5\u201C\u5C0F\u65F6\u201D\u4E3A\u5355\u4F4D\uFF0C\u800C\u4F20\u7EDF\u8F6F\u4EF6\u4EA7\u54C1\u7684\u5468\u671F\u591A\u4EE5\u201C\u6708\u201D\uFF0C\u751A\u81F3\u4EE5\u201C\u5E74\u201D\u4E3A\u5355\u4F4D\u3002</p><p><em>\u53D1\u5E03\u5468\u671F\u7684\u5DE8\u5927\u5DEE\u5F02\u51B3\u5B9A\u4E86\uFF0C\u4F20\u7EDF\u8F6F\u4EF6\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u5FC5\u7136\u4E0D\u9002\u7528\u4E8E\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\uFF0C\u4E8C\u8005\u7684\u6D4B\u8BD5\u7B56\u7565\u5FC5\u7136\u5728\u6D4B\u8BD5\u6267\u884C\u65F6\u95F4\u548C\u6D4B\u8BD5\u6267\u884C\u73AF\u5883\u4E0A\u6709\u5DE8\u5927\u5DEE\u5F02</em>\u3002</p><p>\u6BD4\u5982\uFF0C\u5BF9\u4E8E\u529F\u80FD\u81EA\u52A8\u5316\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u6267\u884C\u4E00\u8F6E\u5168\u56DE\u5F52\u6D4B\u8BD5\u9700\u8981 12 \u5C0F\u65F6\uFF0C\u5BF9\u4F20\u7EDF\u8F6F\u4EF6\u6765\u8BF4\u8FD9\u6839\u672C\u4E0D\u662F\u95EE\u9898\uFF0C\u56E0\u4E3A\u53D1\u5E03\u5468\u671F\u5F88\u957F\uFF0C\u7559\u7ED9\u6D4B\u8BD5\u7684\u65F6\u95F4\u4E5F\u4F1A\u5F88\u5145\u88D5\u3002</p><p>\u4E0D\u8981\u8BF4\u5168\u56DE\u5F52\u6D4B\u8BD5\u6267\u884C\u65F6\u95F4\u9700\u8981 12 \u5C0F\u65F6\uFF0C\u54EA\u6015\u662F\u9700\u8981\u51E0\u5929\u51E0\u591C\u4E5F\u6CA1\u6709\u4EFB\u4F55\u95EE\u9898\uFF0C\u5C31\u50CF\u6211\u4EE5\u524D\u5728\u601D\u79D1\uFF08Cisco\uFF09\u505A\u4F20\u7EDF\u8F6F\u4EF6\u6D4B\u8BD5\u65F6\uFF0C\u4E00\u8F6E\u5B8C\u6574\u7684\u5168\u56DE\u5F52\u6D4B\u8BD5\u7684 GUI \u6D4B\u8BD5\u7528\u4F8B\u6570\u63A5\u8FD1 3000 \u4E2A\uFF0CAPI \u6D4B\u8BD5\u7528\u4F8B\u6570\u66F4\u662F\u63A5\u8FD1 25000 \u4E2A\uFF0C\u8DD1\u5B8C\u5168\u90E8\u7528\u4F8B\u9700\u8981\u5C06\u8FD1 60 \u5C0F\u65F6\u3002</p><p>\u4F46\u5BF9\u4E92\u8054\u7F51\u4EA7\u54C1\u6765\u8BF4\uFF0C\u901A\u5E38 24 \u5C0F\u65F6\u5C31\u4F1A\u6709\u4E00\u5230\u4E24\u6B21\u7684\u53D1\u5E03\uFF0C\u53D1\u5E03\u6D41\u7A0B\u901A\u5E38\u5305\u542B\u4E86\u4EE3\u7801\u9759\u6001\u626B\u63CF\u3001\u5355\u5143\u6D4B\u8BD5\u3001\u7F16\u8BD1\u3001\u6253\u5305\u3001\u4E0A\u4F20\u3001\u4E0B\u8F7D\u3001\u90E8\u7F72\u548C\u6D4B\u8BD5\u7684\u5168\u6D41\u7A0B\u3002\u663E\u7136\u7559\u7ED9\u6D4B\u8BD5\u6267\u884C\u7684\u65F6\u95F4\u5C31\u975E\u5E38\u6709\u9650\uFF0C\u4F20\u7EDF\u8F6F\u4EF6\u52A8\u8F84\u5341\u51E0\u4E2A\u5C0F\u65F6\u7684\u6D4B\u8BD5\u6267\u884C\u65F6\u95F4\uFF0C\u5728\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\u4E0A\uFF0C\u6839\u672C\u884C\u4E0D\u901A\u3002</p><p><strong>\u901A\u5E38\u60C5\u51B5\u4E0B\uFF0C\u4E92\u8054\u7F51\u4EA7\u54C1\u8981\u6C42\u5168\u56DE\u5F52\u6D4B\u8BD5\u7684\u6267\u884C\u65F6\u95F4\u4E0D\u80FD\u8D85\u8FC7 4 \u5C0F\u65F6</strong>\u3002</p><p>\u90A3\u4E48\uFF0C\u5982\u4F55\u5728\u4FDD\u8BC1\u6D4B\u8BD5\u8D28\u91CF\u548C\u6D4B\u8BD5\u8986\u76D6\u7387\u7684\u524D\u63D0\u4E0B\uFF0C\u6709\u6548\u7F29\u77ED\u6D4B\u8BD5\u6267\u884C\u65F6\u95F4\u5462\uFF1F</p><ul><li><p>\u9996\u5148\uFF0C\u4F60\u53EF\u4EE5\u5F15\u5165\u6D4B\u8BD5\u7684\u5E76\u53D1\u6267\u884C\u673A\u5236\uFF0C\u7528\u5305\u542B\u5927\u91CF\u6D4B\u8BD5\u6267\u884C\u8282\u70B9\u7684\u6D4B\u8BD5\u6267\u884C\u96C6\u7FA4\u6765\u5E76\u53D1\u6267\u884C\u6D4B\u8BD5\u7528\u4F8B\u3002 \u6D4B\u8BD5\u6267\u884C\u96C6\u7FA4\uFF0C\u4F60\u53EF\u4EE5\u7B80\u5355\u7406\u89E3\u4E3A\u662F\u4E00\u6279\u4E13\u95E8\u7528\u6765\u5E76\u53D1\u6267\u884C\u6D4B\u8BD5\u7528\u4F8B\u7684\u673A\u5668\u3002\u5E38\u89C1\u7684\u6D4B\u8BD5\u6267\u884C\u96C6\u7FA4\uFF0C\u7531\u4E00\u4E2A\u4E3B\u8282\u70B9\uFF08Master\uFF09\u548C\u82E5\u5E72\u4E2A\u5B50\u8282\u70B9\uFF08Node\uFF09\u7EC4\u6210\u3002\u5176\u4E2D\uFF0C\u4E3B\u8282\u70B9\u7528\u6765\u5206\u53D1\u6D4B\u8BD5\u7528\u4F8B\u5230\u5404\u4E2A\u5B50\u8282\u70B9\uFF0C\u800C\u5404\u4E2A\u5B50\u8282\u70B9\u7528\u6765\u5177\u4F53\u6267\u884C\u6D4B\u8BD5\u7528\u4F8B\u3002 \u76EE\u524D\uFF0C\u5F88\u591A\u4E92\u8054\u7F51\u4F01\u4E1A\u90FD\u5EFA\u7ACB\u4E86\u81EA\u5DF1\u7684\u6D4B\u8BD5\u6267\u884C\u96C6\u7FA4\u3002</p></li><li><p>\u5176\u6B21\uFF0C\u4F60\u5FC5\u987B\u4ECE\u6D4B\u8BD5\u7B56\u7565\u4E0A\u627E\u5230\u7A81\u7834\u53E3\uFF0C\u8FD9\u4E5F\u662F\u6211\u4ECA\u5929\u8DDF\u4F60\u5206\u4EAB\u7684\u4E3B\u9898\u3002</p></li></ul><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u4F1A\u5148\u7B80\u5355\u4E3A\u4F60\u4ECB\u7ECD\u4E00\u4E0B\u4F20\u7EDF\u8F6F\u4EF6\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u8BBE\u8BA1\uFF0C\u7136\u540E\u518D\u7ED9\u4F60\u5206\u4EAB\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\uFF0C\u8FD9\u6837\u53EF\u4EE5\u901A\u8FC7\u5BF9\u4F20\u7EDF\u8F6F\u4EF6\u4EA7\u54C1\u6D4B\u8BD5\u7B56\u7565\u7684\u56DE\u987E\uFF0C\u52A0\u6DF1\u4F60\u5BF9\u4E92\u8054\u7F51\u4EA7\u54C1\u6D4B\u8BD5\u7B56\u7565\u7684\u8BA4\u8BC6\u3002</p><p><strong>\u4F20\u7EDF\u8F6F\u4EF6\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u8BBE\u8BA1</strong></p><p>\u4F20\u7EDF\u8F6F\u4EF6\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\uFF0C\u901A\u5E38\u91C7\u7528\u5982\u56FE 1 \u6240\u793A\u7684\u91D1\u5B57\u5854\u6A21\u578B\u3002\u8BE5\u91D1\u5B57\u5854\u6A21\u578B\u662F\u8FC8\u514B \xB7 \u79D1\u6069\uFF08Mike Cohn\uFF09\u63D0\u51FA\u7684\uFF0C\u5728\u5F88\u957F\u4E00\u6BB5\u65F6\u95F4\u5185\u90FD\u88AB\u8BA4\u4E3A\u662F\u6D4B\u8BD5\u7B56\u7565\u8BBE\u8BA1\u7684\u6700\u4F73\u5B9E\u8DF5\u3002 <img src="https://static001.geekbang.org/resource/image/54/b4/5456dcb2f274e8e04077ee1251ac4ab4.png" alt="\u4F20\u7EDF\u8F6F\u4EF6\u4EA7\u54C1\u7684\u91D1\u5B57\u5854\u6D4B\u8BD5\u7B56\u7565"></p><p><strong>\u7B2C\u4E00\uFF0C\u5355\u5143\u6D4B\u8BD5</strong></p><p>\u91D1\u5B57\u5854\u6700\u5E95\u90E8\u662F\u5355\u5143\u6D4B\u8BD5\uFF0C\u5C5E\u4E8E\u767D\u76D2\u6D4B\u8BD5\u7684\u8303\u7574\uFF0C\u901A\u5E38\u7531\u5F00\u53D1\u5DE5\u7A0B\u5E08\u81EA\u5DF1\u5B8C\u6210\uFF0C\u7531\u4E8E\u8D8A\u65E9\u53D1\u73B0\u7F3A\u9677\u5176\u4FEE\u590D\u6210\u672C\u8D8A\u4F4E\uFF0C\u6240\u4EE5\u4F20\u7EDF\u8F6F\u4EF6\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u63D0\u5021\u5BF9\u5355\u5143\u6D4B\u8BD5\u7684\u9AD8\u6295\u5165\uFF0C\u5355\u5143\u6D4B\u8BD5\u8FD9\u4E00\u5C42\u901A\u5E38\u90FD\u4F1A\u505A\u5F97\u6BD4\u8F83\u201C\u539A\u201D\u3002</p><p>\u53E6\u5916\uFF0C\u4F20\u7EDF\u8F6F\u4EF6\u4EA7\u54C1\uFF0C\u751F\u547D\u5468\u671F\u90FD\u6BD4\u8F83\u957F\uFF0C\u901A\u5E38\u4F1A\u6709\u591A\u4E2A\u7248\u672C\u6301\u7EED\u53D1\u5E03\uFF0C\u4E3A\u4E86\u5728\u540E\u671F\u7684\u7248\u672C\u5347\u7EA7\u8FC7\u7A0B\u4E2D\u80FD\u591F\u5C3D\u65E9\u53D1\u73B0\u5E76\u5FEB\u901F\u5B9A\u4F4D\u95EE\u9898\uFF0C\u6BCF\u6B21 build \u8FC7\u7A0B\u4E2D\u90FD\u4F1A\u591A\u6B21\u53CD\u590D\u6267\u884C\u5355\u5143\u6D4B\u8BD5\uFF0C\u8FD9\u4E5F\u4ECE\u53E6\u4E00\u4E2A\u89D2\u5EA6\u53CD\u6620\u51FA\u5355\u5143\u6D4B\u8BD5\u7684\u91CD\u8981\u6027\u3002</p><p><strong>\u7B2C\u4E8C\uFF0CAPI \u6D4B\u8BD5</strong></p><p><strong>\u91D1\u5B57\u5854\u4E2D\u95F4\u90E8\u5206\u662F API \u6D4B\u8BD5\uFF0C\u4E3B\u8981\u9488\u5BF9\u7684\u662F\u5404\u6A21\u5757\u66B4\u9732\u7684\u63A5\u53E3\uFF0C\u901A\u5E38\u91C7\u7528\u7070\u76D2\u6D4B\u8BD5\u65B9\u6CD5\u3002\u7070\u76D2\u6D4B\u8BD5\u65B9\u6CD5\u662F\u4ECB\u4E8E\u767D\u76D2\u6D4B\u8BD5\u548C\u9ED1\u76D2\u6D4B\u8BD5\u4E4B\u95F4\u7684\u4E00\u79CD\u6D4B\u8BD5\u6280\u672F\uFF0C\u5176\u6838\u5FC3\u601D\u60F3\u662F\u5229\u7528\u6D4B\u8BD5\u6267\u884C\u7684\u4EE3\u7801\u8986\u76D6\u7387\u6765\u6307\u5BFC\u6D4B\u8BD5\u7528\u4F8B\u7684\u8BBE\u8BA1</strong>\u3002</p><p>\u4EE5 API \u63A5\u53E3\u6D4B\u8BD5\u4E3A\u4F8B\uFF0C\u9996\u5148\u4EE5\u9ED1\u76D2\u65B9\u5F0F\u8BBE\u8BA1\u5982\u4F55\u8C03\u7528 API \u7684\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u540C\u65F6\u5728\u6D4B\u8BD5\u6267\u884C\u8FC7\u7A0B\u4E2D\u7EDF\u8BA1\u4EE3\u7801\u8986\u76D6\u7387\uFF0C\u7136\u540E\u6839\u636E\u4EE3\u7801\u8986\u76D6\u7387\u60C5\u51B5\u6765\u8865\u5145\u66F4\u591A\u3001\u66F4\u6709\u9488\u5BF9\u6027\u7684\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u603B\u4F53\u6765\u770B\uFF0CAPI \u6D4B\u8BD5\u7528\u4F8B\u7684\u6570\u91CF\u4F1A\u5C11\u4E8E\u5355\u5143\u6D4B\u8BD5\uFF0C\u4F46\u591A\u4E8E\u4E0A\u5C42\u7684 GUI \u6D4B\u8BD5\u3002</p><p><strong>\u7B2C\u4E09\uFF0CGUI \u6D4B\u8BD5</strong></p><p>\u91D1\u5B57\u5854\u6700\u4E0A\u5C42\u7684\u662F GUI \u6D4B\u8BD5\uFF0C\u4E5F\u79F0\u4E3A\u7AEF\u5230\u7AEF\uFF08E2E\uFF0CEnd-to-end\uFF09\u6D4B\u8BD5\uFF0C\u662F\u6700\u63A5\u8FD1\u8F6F\u4EF6\u771F\u5B9E\u7528\u6237\u4F7F\u7528\u884C\u4E3A\u7684\u6D4B\u8BD5\u7C7B\u578B\u3002\u901A\u5E38\u662F\u6A21\u62DF\u771F\u5B9E\u7528\u6237\u4F7F\u7528\u8F6F\u4EF6\u7684\u884C\u4E3A\uFF0C\u5373\u6A21\u62DF\u7528\u6237\u5728\u8F6F\u4EF6\u754C\u9762\u4E0A\u7684\u5404\u79CD\u64CD\u4F5C\uFF0C\u5E76\u9A8C\u8BC1\u8FD9\u4E9B\u64CD\u4F5C\u5BF9\u5E94\u7684\u7ED3\u679C\u662F\u5426\u6B63\u786E\u3002</p><p>GUI \u6D4B\u8BD5\u7684\u4F18\u70B9\u662F\uFF0C\u80FD\u591F\u5B9E\u9645\u6A21\u62DF\u771F\u5B9E\u7528\u6237\u7684\u884C\u4E3A\uFF0C\u76F4\u63A5\u9A8C\u8BC1\u8F6F\u4EF6\u7684\u5546\u4E1A\u4EF7\u503C\uFF1B\u7F3A\u70B9\u662F\u6267\u884C\u7684\u4EE3\u4EF7\u6BD4\u8F83\u5927\uFF0C\u5C31\u7B97\u662F\u91C7\u7528 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u6280\u672F\uFF0C\u7528\u4F8B\u7684\u7EF4\u62A4\u548C\u6267\u884C\u4EE3\u4EF7\u4F9D\u7136\u5F88\u5927\u3002\u6240\u4EE5\uFF0C\u8981\u5C3D\u53EF\u80FD\u5730\u907F\u514D\u5BF9 GUI \u6D4B\u8BD5\u7684\u8FC7\u5EA6\u4F9D\u8D56\u3002</p><p>\u53E6\u5916\uFF0CGUI \u6D4B\u8BD5\u7684\u7A33\u5B9A\u6027\u95EE\u9898\uFF0C\u662F\u957F\u671F\u4EE5\u6765\u963B\u788D GUI \u6D4B\u8BD5\u53D1\u5C55\u7684\u91CD\u8981\u539F\u56E0\u3002\u5373\u4F7F\u4F60\u91C7\u7528\u4E86\u5F88\u591A\u8BF8\u5982 retry \u673A\u5236\u4EE5\u53CA\u5F02\u5E38\u573A\u666F\u6062\u590D\u673A\u5236\u7B49\u65B9\u5F0F\uFF0CGUI \u6D4B\u8BD5\u7684\u968F\u673A\u5931\u8D25\u7387\u4F9D\u65E7\u9AD8\u5C45\u4E0D\u4E0B\u3002</p><p><strong>\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u8BBE\u8BA1</strong></p><p>\u5BF9\u4E8E\u4E92\u8054\u7F51\u4EA7\u54C1\u6765\u8BF4\uFF0C\u8FC8\u514B\u7684\u91D1\u5B57\u5854\u6A21\u578B\u5DF2\u7ECF\u4E0D\u518D\u9002\u7528\uFF0C\u6211\u4F1A\u901A\u8FC7 GUI \u6D4B\u8BD5\u3001API \u6D4B\u8BD5\u3001\u5355\u5143\u6D4B\u8BD5\u8FD9\u4E09\u4E2A\u65B9\u9762\uFF0C\u6765\u8DDF\u4F60\u804A\u804A\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u6709\u54EA\u4E9B\u53D8\u5316\uFF0C\u5E94\u8BE5\u5982\u4F55\u8BBE\u8BA1\u3002</p><p><strong>\u7B2C\u4E00\uFF0CGUI \u6D4B\u8BD5</strong></p><p>\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u4E0A\u7EBF\u5468\u671F\uFF0C\u51B3\u5B9A\u4E86 GUI \u6D4B\u8BD5\u4E0D\u53EF\u80FD\u5927\u8303\u56F4\u5F00\u5C55\u3002</p><ol><li>\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u8FED\u4EE3\u5468\u671F\uFF0C\u51B3\u5B9A\u4E86\u7559\u7ED9\u5F00\u53D1 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u7528\u4F8B\u7684\u65F6\u95F4\u975E\u5E38\u6709\u9650\uFF1B</li><li>\u4E92\u8054\u7F51\u4EA7\u54C1\u5BA2\u6237\u7AEF\u754C\u9762\u7684\u9891\u7E41\u53D8\u5316\uFF0C\u51B3\u5B9A\u4E86\u5F00\u5C55 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u7684\u6548\u7387\u4F1A\u975E\u5E38\u4F4E\uFF0C\u8FD9\u4E5F\u662F\u6700\u7CDF\u7CD5\u7684\u3002 \u56E0\u4E3A\u654F\u6377\u6A21\u5F0F\u4E0B\u7684\u5FEB\u901F\u53CD\u9988\uFF0C\u5728\u4E0B\u4E00\u4E2A\u8FED\u4EE3\uFF08sprint\uFF09\u53EF\u80FD\u5C31\u9700\u8981\u6839\u636E\u53CD\u9988\u6765\u505A\u4FEE\u6539\u548C\u8C03\u6574\u5BA2\u6237\u7AEF\u754C\u9762\uFF0C\u90A3\u4E48\u521A\u5F00\u53D1\u5B8C\uFF0C\u751A\u81F3\u662F\u8FD8\u6CA1\u5F00\u53D1\u5B8C\u7684 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u7528\u4F8B\u5C31\u8981\u8DDF\u7740\u4E00\u8D77\u4FEE\u6539\u3002 \u8FD9\u79CD\u9891\u7E41\u5730\u4FEE\u6539\uFF0C\u5BF9\u5F00\u53D1 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u662F\u975E\u5E38\u4E0D\u5229\u7684\u3002\u56E0\u4E3A\uFF0C\u521A\u5F00\u53D1\u5B8C\u7684\u81EA\u52A8\u5316\u7528\u4F8B\u53EA\u8DD1\u4E86\u4E00\u6B21\uFF0C\u751A\u81F3\u662F\u4E00\u6B21\u8FD8\u6CA1\u6765\u5F97\u53CA\u8DD1\u5C31\u9700\u8981\u66F4\u65B0\u4E86\uFF0C\u5BFC\u81F4 GUI \u81EA\u52A8\u5316\u6D4B\u8BD5\u8FD8\u4E0D\u5982\u624B\u5DE5\u6D4B\u8BD5\u7684\u6548\u7387\u9AD8\u3002</li></ol><p>\u7531\u6B64\uFF0C<strong>\u4E92\u8054\u7F51\u4EA7\u54C1\u7684 GUI \u6D4B\u8BD5\u901A\u5E38\u91C7\u7528\u201C\u624B\u5DE5\u4E3A\u4E3B\uFF0C\u81EA\u52A8\u5316\u4E3A\u8F85\u201D\u7684\u6D4B\u8BD5\u7B56\u7565\uFF0C\u624B\u5DE5\u6D4B\u8BD5\u5F80\u5F80\u5229\u7528\u63A2\u7D22\u6027\u6D4B\u8BD5\u601D\u60F3\uFF0C\u9488\u5BF9\u65B0\u5F00\u53D1\u6216\u8005\u65B0\u4FEE\u6539\u7684\u754C\u9762\u529F\u80FD\u8FDB\u884C\u6D4B\u8BD5\uFF0C\u800C\u81EA\u52A8\u5316\u6D4B\u8BD5\u7684\u5173\u6CE8\u70B9\u4E3B\u8981\u653E\u5728\u76F8\u5BF9\u7A33\u5B9A\u4E14\u6838\u5FC3\u4E1A\u52A1\u7684\u57FA\u672C\u529F\u80FD\u9A8C\u8BC1\u4E0A\u3002\u6240\u4EE5\uFF0CGUI \u7684\u81EA\u52A8\u5316\u6D4B\u8BD5\u5F80\u5F80\u53EA\u8986\u76D6\u6700\u6838\u5FC3\u4E14\u76F4\u63A5\u5F71\u54CD\u4E3B\u8425\u4E1A\u52A1\u6D41\u7A0B\u7684 E2E \u573A\u666F</strong>\u3002</p><p>\u53E6\u5916\uFF0C\u4ECE GUI \u6D4B\u8BD5\u7528\u4F8B\u7684\u6570\u91CF\u6765\u770B\uFF0C\u4F20\u7EDF\u8F6F\u4EF6\u7684 GUI \u6D4B\u8BD5\u5C5E\u4E8E\u91CD\u91CF\u7EA7\u7684\uFF0C\u52A8\u4E0D\u52A8\u5C31\u6709\u4E0A\u5343\u4E2A\u7528\u4F8B\uFF0C\u56E0\u4E3A\u4F20\u7EDF\u8F6F\u4EF6\u7684\u6D4B\u8BD5\u5468\u671F\u5F88\u957F\uFF0C\u6D4B\u8BD5\u7528\u4F8B\u53EF\u4EE5\u8F6E\u6D41\u6392\u961F\u6162\u6162\u6267\u884C\uFF0C\u65F6\u95F4\u957F\u70B9\u4E5F\u6CA1\u5173\u7CFB\u3002</p><p>\u800C\u4E92\u8054\u7F51\u4EA7\u54C1\u8981\u6C42 GUI \u6D4B\u8BD5\u662F\u8F7B\u91CF\u7EA7\u7684\uFF0C\u4F60\u89C1\u8FC7\u6216\u8005\u542C\u8FC7\u6709\u54EA\u4E2A\u4E92\u8054\u7F51\u4EA7\u54C1\u8BBE\u8BA1\u4E86\u4E0A\u5343\u4E2A GUI \u6D4B\u8BD5\u7528\u4F8B\u5417\uFF1F\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u4E0A\u7EBF\u5468\u671F\uFF0C\u76F4\u63A5\u51B3\u5B9A\u4E86\u4E0D\u5141\u8BB8\u4F60\u53BB\u6267\u884C\u5927\u91CF\u7684\u7528\u4F8B\u3002</p><p><strong>\u7B2C\u4E8C\uFF0CAPI \u6D4B\u8BD5</strong></p><p>\u4F60\u73B0\u5728\u53EF\u80FD\u8981\u95EE\uFF0C\u65E2\u7136\u4E92\u8054\u7F51\u4EA7\u54C1\u4E0D\u9002\u5B9C\u505A\u91CD\u91CF\u7EA7\u7684 GUI \u6D4B\u8BD5\uFF0C\u90A3\u4E48\u600E\u6837\u624D\u80FD\u4FDD\u8BC1\u5176\u8D28\u91CF\u5462\uFF1F</p><p>\u5176\u5B9E\uFF0C\u5BF9\u4E8E\u4E92\u8054\u7F51\u4EA7\u54C1\u6765\u8BF4\uFF0C\u628A\u6D4B\u8BD5\u91CD\u70B9\u653E\u5728 API \u6D4B\u8BD5\u4E0A\uFF0C\u624D\u662F\u6700\u660E\u667A\u7684\u9009\u62E9\u3002\u4E3A\u4EC0\u4E48\u5462\uFF1F\u6211\u7ED9\u4F60\u603B\u7ED3\u4E86\u4EE5\u4E0B\u4E94\u6761\u539F\u56E0\u3002</p><ol><li><strong>API \u6D4B\u8BD5\u7528\u4F8B\u7684\u5F00\u53D1\u4E0E\u8C03\u8BD5\u6548\u7387\u6BD4 GUI \u6D4B\u8BD5\u8981\u9AD8\u5F97\u591A</strong>\uFF0C\u800C\u4E14\u6D4B\u8BD5\u7528\u4F8B\u7684\u4EE3\u7801\u5B9E\u73B0\u6BD4\u8F83\u89C4\u8303\uFF0C\u901A\u5E38\u5C31\u662F\u51C6\u5907\u6D4B\u8BD5\u6570\u636E\uFF0C\u53D1\u8D77 request\uFF0C\u9A8C\u8BC1 response \u8FD9\u51E0\u4E2A\u6807\u51C6\u6B65\u9AA4\u3002</li><li><strong>API \u6D4B\u8BD5\u7528\u4F8B\u7684\u6267\u884C\u7A33\u5B9A\u6027\u8FDC\u8FDC\u9AD8\u4E8E GUI \u6D4B\u8BD5</strong>\u3002 GUI \u6D4B\u8BD5\u6267\u884C\u7684\u7A33\u5B9A\u6027\u59CB\u7EC8\u662F\u96BE\u9898\uFF0C\u5373\u4F7F\u4F60\u91C7\u7528\u4E86\u5F88\u591A\u6280\u672F\u624B\u6BB5\uFF08\u8FD9\u4E9B\u5177\u4F53\u7684\u6280\u672F\u624B\u6BB5\uFF0C\u6211\u4F1A\u5728\u8BB2\u89E3 GUI \u6D4B\u8BD5\u65F6\u518D\u8BE6\u7EC6\u5C55\u5F00\uFF09\uFF0C\u5B83\u4E5F\u65E0\u6CD5\u505A\u5230 100%\u7684\u7A33\u5B9A\u3002 \u800C API \u6D4B\u8BD5\u5929\u751F\u5C31\u6CA1\u6709\u6267\u884C\u7A33\u5B9A\u6027\u7684\u95EE\u9898\uFF0C\u56E0\u4E3A\u6D4B\u8BD5\u6267\u884C\u8FC7\u7A0B\u4E0D\u4F9D\u8D56\u4E8E\u4EFB\u4F55\u754C\u9762\u4E0A\u7684\u64CD\u4F5C\uFF0C\u800C\u662F\u76F4\u63A5\u8C03\u7528\u540E\u7AEF API\uFF0C\u4E14\u8C03\u7528\u8FC7\u7A0B\u6BD4\u8F83\u6807\u51C6\u3002</li><li>\u5355\u4E2A API \u6D4B\u8BD5\u7528\u4F8B\u7684\u6267\u884C\u65F6\u95F4\u5F80\u5F80\u8981\u6BD4 GUI \u6D4B\u8BD5\u77ED\u5F88\u591A\u3002\u5F53\u6709\u5927\u91CF API \u6D4B\u8BD5\u9700\u8981\u6267\u884C\u65F6\uFF0CAPI \u6D4B\u8BD5\u53EF\u4EE5\u5F88\u65B9\u4FBF\u5730\u4EE5\u5E76\u53D1\u7684\u65B9\u5F0F\u6267\u884C\uFF0C\u6240\u4EE5\u53EF\u4EE5\u5728\u77ED\u65F6\u95F4\u5185\u5B8C\u6210\u5927\u6279\u91CF API \u6D4B\u8BD5\u7528\u4F8B\u7684\u6267\u884C\u3002</li><li>\u73B0\u5728\u5F88\u591A\u4E92\u8054\u7F51\u4EA7\u54C1\u91C7\u7528\u4E86\u5FAE\u670D\u52A1\u67B6\u6784\uFF0C\u800C\u5BF9\u5FAE\u670D\u52A1\u7684\u6D4B\u8BD5\uFF0C\u672C\u8D28\u4E0A\u5C31\u662F\u5BF9\u4E0D\u540C\u7684 Web Service \u7684\u6D4B\u8BD5\uFF0C\u4E5F\u5C31\u662F API \u6D4B\u8BD5\u3002 \u5728\u5FAE\u670D\u52A1\u67B6\u6784\u4E0B\uFF0C\u5BA2\u6237\u7AEF\u5E94\u7528\u7684\u5B9E\u73B0\u90FD\u662F\u57FA\u4E8E\u5BF9\u540E\u7AEF\u5FAE\u670D\u52A1\u7684\u8C03\u7528\uFF0C\u5982\u679C\u505A\u597D\u4E86\u6BCF\u4E2A\u540E\u7AEF\u670D\u52A1\u7684\u6D4B\u8BD5\uFF0C\u4F60\u5C31\u4F1A\u5BF9\u5E94\u7528\u7684\u6574\u4F53\u8D28\u91CF\u6709\u5145\u5206\u7684\u4FE1\u5FC3\u3002\u6240\u4EE5\uFF0C\u4E92\u8054\u7F51\u4EA7\u54C1\u7684 API \u6D4B\u8BD5\u975E\u5E38\u91CD\u8981\u3002</li><li>API \u63A5\u53E3\u7684\u6539\u52A8\u4E00\u822C\u6BD4\u8F83\u5C11\uFF0C\u5373\u4F7F\u6709\u6539\u52A8\uFF0C\u7EDD\u5927\u591A\u6570\u60C5\u51B5\u4E0B\u4E5F\u9700\u8981\u4FDD\u8BC1\u540E\u5411\u517C\u5BB9\u6027\uFF08Backward Compatibility\uFF09\u3002\u6240\u8C13\u540E\u5411\u517C\u5BB9\u6027\uFF0C\u6700\u57FA\u672C\u7684\u8981\u6C42\u5C31\u662F\u4FDD\u8BC1\u539F\u672C\u7684 API \u8C03\u7528\u65B9\u5F0F\u7EF4\u6301\u4E0D\u53D8\u3002 \u663E\u7136\uFF0C\u5982\u679C\u8C03\u7528\u65B9\u5F0F\u6CA1\u6709\u53D1\u751F\u53D8\u5316\uFF0C\u90A3\u4E48\u539F\u672C\u7684 API \u6D4B\u8BD5\u7528\u4F8B\u4E5F\u5C31\u4E0D\u9700\u8981\u505A\u5927\u7684\u6539\u52A8\uFF0C\u8FD9\u6837\u7528\u4F8B\u7684\u53EF\u91CD\u7528\u6027\u5C31\u5F88\u9AD8\uFF0C\u8FDB\u800C\u53EF\u4EE5\u4FDD\u8BC1\u8F83\u9AD8\u7684\u6295\u5165\u4EA7\u51FA\u6BD4\uFF08ROI\uFF09\u3002</li></ol><p>\u53EF\u89C1\uFF0C<strong>\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u8FD9\u4E9B\u7279\u6027\u51B3\u5B9A\u4E86\uFF0CAPI \u6D4B\u8BD5\u53EF\u4EE5\u5B9E\u73B0\u826F\u597D\u7684\u6295\u5165\u4EA7\u51FA\u6BD4\uFF0C\u56E0\u6B64\u5E94\u8BE5\u6210\u4E3A\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\u91CD\u70B9\u3002\u8FD9\u4E5F\u5C31\u662F\u4E3A\u4EC0\u4E48\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u6D4B\u8BD5\u7B56\u7565\u66F4\u50CF\u662F\u4E2A\u83F1\u5F62\u7ED3\u6784\u7684\u539F\u56E0</strong>\u3002</p><p>\u5982\u56FE 2 \u6240\u793A\u5C31\u662F\u8FD9\u4E2A\u83F1\u5F62\u7684\u6D4B\u8BD5\u7B56\u7565\uFF0C\u9075\u5FAA\u201C<strong>\u91CD\u91CF\u7EA7 API \u6D4B\u8BD5\uFF0C\u8F7B\u91CF\u7EA7 GUI \u6D4B\u8BD5\uFF0C\u8F7B\u91CF\u7EA7\u5355\u5143\u6D4B\u8BD5</strong>\u201D\u7684\u539F\u5219\u3002 <img src="https://static001.geekbang.org/resource/image/c7/cd/c72e5900d670f779c5dd6827407032cd.png" alt="\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u83F1\u5F62\u6D4B\u8BD5\u7B56\u7565"></p><p><strong>\u7B2C\u4E09\uFF0C\u5355\u5143\u6D4B\u8BD5</strong></p><p>\u4E86\u89E3\u4E86\u201C\u91CD\u91CF\u7EA7 API \u6D4B\u8BD5\u201D\u548C\u201C\u8F7B\u91CF\u7EA7 GUI \u6D4B\u8BD5\u201D\uFF0C\u63A5\u4E0B\u6765\uFF0C\u6211\u5C31\u8DDF\u4F60\u8BF4\u8BF4\u4E3A\u4EC0\u4E48\u662F\u201C\u8F7B\u91CF\u7EA7\u5355\u5143\u6D4B\u8BD5\u201D\u3002</p><p>\u4ECE\u7406\u8BBA\u4E0A\u8BB2\uFF0C\u65E0\u8BBA\u662F\u4F20\u7EDF\u8F6F\u4EF6\u4EA7\u54C1\u8FD8\u662F\u4E92\u8054\u7F51\u4EA7\u54C1\uFF0C\u5355\u5143\u6D4B\u8BD5\u90FD\u662F\u4ECE\u6E90\u5934\u4FDD\u8BC1\u8F6F\u4EF6\u8D28\u91CF\u7684\u91CD\u8981\u624B\u6BB5\uFF0C\u56E0\u6B64\u90FD\u975E\u5E38\u91CD\u8981\u3002\u4F46\u73B0\u5B9E\u662F\uFF0C\u4E92\u8054\u7F51\u4EA7\u54C1\u771F\u6B63\u80FD\u5168\u9762\u5F00\u5C55\u5355\u5143\u6D4B\u8BD5\uFF0C\u5E76\u4E25\u683C\u63A7\u5236\u4EE3\u7801\u8986\u76D6\u7387\u7684\u4F01\u4E1A\u8FD8\u662F\u51E4\u6BDB\u9E9F\u89D2\u3002</p><p>\u4F46\u51E1\u5B58\u5728\u7684\u90FD\u4F1A\u6709\u5176\u5408\u7406\u6027\uFF0C\u6211\u8BA4\u4E3A\u6700\u4E3B\u8981\u7684\u539F\u56E0\u8FD8\u662F\u5728\u4E8E\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u201C\u5FEB\u201D\uFF0C\u5FEB\u901F\u5B9E\u73B0\u529F\u80FD\uFF0C\u5FEB\u901F\u5BFB\u6C42\u7528\u6237\u53CD\u9988\uFF0C\u5FEB\u901F\u8BD5\u9519\uFF0C\u5FEB\u901F\u8FED\u4EE3\u66F4\u65B0\u3002</p><p>\u5728\u8FD9\u6837\u7684\u6A21\u5F0F\u4E0B\uFF0C\u4E92\u8054\u7F51\u4EA7\u54C1\u8FFD\u6C42\u7684\u662F\u6700\u5FEB\u901F\u7684\u529F\u80FD\u5B9E\u73B0\u5E76\u4E0A\u7EBF\uFF0C\u57FA\u672C\u4E0D\u4F1A\u7ED9\u4F60\u65F6\u95F4\u53BB\u505A\u5168\u9762\u7684\u5355\u5143\u6D4B\u8BD5\u3002\u5373\u4F7F\u7ED9\u4F60\u9884\u7559\u4E86\u5355\u5143\u6D4B\u8BD5\u7684\u65F6\u95F4\uFF0C\u9891\u7E41\u7684\u8FED\u4EE3\u4E5F\u4F1A\u8BA9\u5355\u5143\u6D4B\u8BD5\u5904\u4E8E\u4E0D\u65AD\u91CD\u5199\u7684\u72B6\u6001\u3002\u56E0\u6B64\uFF0C\u5355\u5143\u6D4B\u8BD5\u539F\u672C\u7684\u4EF7\u503C\uFF0C\u5F88\u96BE\u5728\u5B9E\u9645\u64CD\u4F5C\u5C42\u9762\u5F97\u5230\u4F53\u73B0\u3002</p><p><strong>\u90A3\u4E48\uFF0C\u4E92\u8054\u7F51\u4EA7\u54C1\u771F\u7684\u53EF\u4EE5\u4E0D\u7528\u505A\u5355\u5143\u6D4B\u8BD5\u4E48\uFF1F\u7B54\u6848\u662F\u5426\u5B9A\u7684\uFF0C\u53EA\u4E0D\u662F\u8FD9\u91CC\u7684\u5355\u5143\u6D4B\u8BD5\u7B56\u7565\u8981\u91C7\u7528\u201C\u5206\u800C\u6CBB\u4E4B\u201D\u7684\u601D\u60F3</strong>\u3002</p><p>\u4E92\u8054\u7F51\u4EA7\u54C1\u901A\u5E38\u4F1A\u5206\u4E3A\u5E94\u7528\u5C42\u548C\u540E\u7AEF\u670D\u52A1\uFF0C\u540E\u7AEF\u670D\u52A1\u53C8\u53EF\u4EE5\u8FDB\u4E00\u6B65\u7EC6\u5206\u4E3A\u5E94\u7528\u670D\u52A1\u548C\u57FA\u7840\u670D\u52A1\u3002</p><p>\u540E\u7AEF\u57FA\u7840\u670D\u52A1\u548C\u4E00\u4E9B\u516C\u5171\u5E94\u7528\u670D\u52A1\u76F8\u5BF9\u7A33\u5B9A\uFF0C\u800C\u4E14\u5BF9\u4E8E\u7CFB\u7EDF\u5168\u5C40\u6765\u8BF4\u662F\u201C\u7275\u4E00\u53D1\u800C\u52A8\u5168\u8EAB\u201D\uFF0C\u6240\u4EE5\u540E\u7AEF\u670D\u52A1\u5F88\u6709\u5FC5\u8981\u5F00\u5C55\u5168\u9762\u7684\u5355\u5143\u6D4B\u8BD5\uFF1B\u800C\u5BF9\u4E8E\u53D8\u52A8\u975E\u5E38\u9891\u7E41\u7684\u5BA2\u6237\u7AEF\u5E94\u7528\u548C\u975E\u516C\u7528\u7684\u540E\u7AEF\u5E94\u7528\u670D\u52A1\uFF0C\u4E00\u822C\u5F88\u5C11\u4F1A\u53BB\u505A\u5355\u5143\u6D4B\u8BD5\u3002</p><p>\u53E6\u5916\uFF0C\u5BF9\u4E8E\u4E00\u4E9B\u6838\u5FC3\u7B97\u6CD5\u548C\u5173\u952E\u5E94\u7528\uFF0C\u6BD4\u5982\u94F6\u884C\u7F51\u5173\u63A5\u53E3\uFF0C\u7B2C\u4E09\u65B9\u652F\u4ED8\u96C6\u6210\u63A5\u53E3\u7B49\uFF0C\u4E5F\u8981\u505A\u6BD4\u8F83\u5168\u9762\u7684\u5355\u5143\u6D4B\u8BD5\u3002</p><p><strong>\u603B\u7ED3\u6765\u8BB2\uFF0C\u4E92\u8054\u7F51\u4EA7\u54C1\u7684\u5168\u9762\u5355\u5143\u6D4B\u8BD5\u53EA\u4F1A\u5E94\u7528\u5728\u90A3\u4E9B\u76F8\u5BF9\u7A33\u5B9A\u548C\u6700\u6838\u5FC3\u7684\u6A21\u5757\u548C\u670D\u52A1\u4E0A\uFF0C\u800C\u5E94\u7528\u5C42\u6216\u8005\u4E0A\u5C42\u4E1A\u52A1\u670D\u52A1\u5F88\u5C11\u4F1A\u5927\u89C4\u6A21\u5F00\u5C55\u5355\u5143\u6D4B\u8BD5</strong>\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u4F20\u7EDF\u8F6F\u4EF6\u901A\u5E38\u91C7\u7528\u91D1\u5B57\u5854\u6A21\u578B\u7684\u6D4B\u8BD5\u7B56\u7565\uFF0C\u800C\u73B0\u4ECA\u7684\u4E92\u8054\u7F51\u4EA7\u54C1\u5F80\u5F80\u91C7\u7528\u83F1\u5F62\u6A21\u578B\u3002\u83F1\u5F62\u6A21\u578B\u6709\u4EE5\u4E0B\u56DB\u4E2A\u5173\u952E\u70B9\uFF1A</p><ul><li>\u4EE5\u4E2D\u95F4\u5C42\u7684 API \u6D4B\u8BD5\u4E3A\u91CD\u70B9\u505A\u5168\u9762\u7684\u6D4B\u8BD5\u3002</li><li>\u8F7B\u91CF\u7EA7\u7684 GUI \u6D4B\u8BD5\uFF0C\u53EA\u8986\u76D6\u6700\u6838\u5FC3\u76F4\u63A5\u5F71\u54CD\u4E3B\u8425\u4E1A\u52A1\u6D41\u7A0B\u7684 E2E \u573A\u666F\u3002</li><li>\u6700\u4E0A\u5C42\u7684 GUI \u6D4B\u8BD5\u901A\u5E38\u5229\u7528\u63A2\u7D22\u5F0F\u6D4B\u8BD5\u601D\u7EF4\uFF0C\u4EE5\u4EBA\u5DE5\u6D4B\u8BD5\u7684\u65B9\u5F0F\u53D1\u73B0\u5C3D\u53EF\u80FD\u591A\u7684\u6F5C\u5728\u95EE\u9898\u3002</li><li>\u5355\u5143\u6D4B\u8BD5\u91C7\u7528\u201C\u5206\u800C\u6CBB\u4E4B\u201D\u7684\u601D\u60F3\uFF0C\u53EA\u5BF9\u90A3\u4E9B\u76F8\u5BF9\u7A33\u5B9A\u5E76\u4E14\u6838\u5FC3\u7684\u670D\u52A1\u548C\u6A21\u5757\u5F00\u5C55\u5168\u9762\u7684\u5355\u5143\u6D4B\u8BD5\uFF0C\u800C\u5E94\u7528\u5C42\u6216\u8005\u4E0A\u5C42\u4E1A\u52A1\u53EA\u4F1A\u505A\u5C11\u91CF\u7684\u5355\u5143\u6D4B\u8BD5\u3002</li></ul><p><strong>\u601D\u8003\u9898</strong></p><p>\u4F60\u6240\u5728\u7684\u516C\u53F8\u6216\u8005\u4EA7\u54C1\u7EBF\uFF0C\u91C7\u7528\u7684\u662F\u4EC0\u4E48\u6D4B\u8BD5\u7B56\u7565\uFF1F\u770B\u5B8C\u4E86\u672C\u7BC7\u6587\u7AE0\uFF0C\u4F60\u4F1A\u5982\u4F55\u8BC4\u4EF7\u4F60\u4EEC\u516C\u53F8\u7684\u6D4B\u8BD5\u7B56\u7565\u5462\uFF1F\u6709\u54EA\u4E9B\u597D\u7684\u5730\u65B9\uFF0C\u53C8\u6709\u54EA\u4E9B\u5730\u65B9\u9700\u8981\u6539\u8FDB\uFF1F</p>',57);function o(n,I){return s}var e=p(r,[["render",o],["__file","11.html.vue"]]);export{e as default};
